$pythonCode = @'
import json
def premiers(n):
    primes = []
    candidate = 2
    while len(primes) < n:
        if all(candidate % p != 0 for p in primes):
            primes.append(candidate)
        candidate += 1
    return primes
print(json.dumps(premiers(5)))
'@

$tmpFile = [System.IO.Path]::GetTempFileName() + '.py'
Set-Content $tmpFile $pythonCode
try {
    $result = python3 $tmpFile 2>$null ?? (python $tmpFile)
    $primes = $result | ConvertFrom-Json
    Write-Host "Nombres premiers : $($primes -join ' ')"
} finally {
    Remove-Item $tmpFile -ErrorAction SilentlyContinue
}
